const TYPES = ["Normal","Fire","Water","Electric","Grass","Ice","Fighting","Poison","Ground","Flying","Psychic","Bug","Rock","Ghost","Dragon","Dark","Steel","Fairy"];

// Effectiveness: atk[def] => multiplier. Only store non-1x entries.
const EFF = {
  Normal:   {Rock:0.5, Ghost:0, Steel:0.5},
  Fire:     {Fire:0.5, Water:0.5, Grass:2, Ice:2, Bug:2, Rock:0.5, Dragon:0.5, Steel:2},
  Water:    {Fire:2, Water:0.5, Grass:0.5, Ground:2, Rock:2, Dragon:0.5},
  Electric: {Water:2, Electric:0.5, Grass:0.5, Ground:0, Flying:2, Dragon:0.5},
  Grass:    {Fire:0.5, Water:2, Grass:0.5, Poison:0.5, Ground:2, Flying:0.5, Bug:0.5, Rock:2, Dragon:0.5, Steel:0.5},
  Ice:      {Fire:0.5, Water:0.5, Grass:2, Ice:0.5, Ground:2, Flying:2, Dragon:2, Steel:0.5},
  Fighting: {Normal:2, Ice:2, Poison:0.5, Flying:0.5, Psychic:0.5, Bug:0.5, Rock:2, Ghost:0, Dark:2, Steel:2, Fairy:0.5},
  Poison:   {Grass:2, Poison:0.5, Ground:0.5, Rock:0.5, Ghost:0.5, Steel:0, Fairy:2},
  Ground:   {Fire:2, Electric:2, Grass:0.5, Poison:2, Flying:0, Bug:0.5, Rock:2, Steel:2},
  Flying:   {Electric:0.5, Grass:2, Fighting:2, Bug:2, Rock:0.5, Steel:0.5},
  Psychic:  {Fighting:2, Poison:2, Psychic:0.5, Dark:0, Steel:0.5},
  Bug:      {Fire:0.5, Grass:2, Fighting:0.5, Poison:0.5, Flying:0.5, Psychic:2, Ghost:0.5, Dark:2, Steel:0.5, Fairy:0.5},
  Rock:     {Fire:2, Ice:2, Fighting:0.5, Ground:0.5, Flying:2, Bug:2, Steel:0.5},
  Ghost:    {Normal:0, Psychic:2, Ghost:2, Dark:0.5},
  Dragon:   {Dragon:2, Steel:0.5, Fairy:0},
  Dark:     {Fighting:0.5, Psychic:2, Ghost:2, Dark:0.5, Fairy:0.5},
  Steel:    {Fire:0.5, Water:0.5, Electric:0.5, Ice:2, Rock:2, Steel:0.5, Fairy:2},
  Fairy:    {Fire:0.5, Poison:0.5, Fighting:2, Dragon:2, Dark:2, Steel:0.5}
};

function getEffectiveness(atkType, defType1, defType2) {
  let mult = 1;
  mult *= (EFF[atkType] && EFF[atkType][defType1] !== undefined) ? EFF[atkType][defType1] : 1;
  if (defType2) {
    mult *= (EFF[atkType] && EFF[atkType][defType2] !== undefined) ? EFF[atkType][defType2] : 1;
  }
  return mult;
}

// ============================================================
// MEGA LINKAGE â base id -> mega id(s), and reverse
// ============================================================
const MEGA_MAP = {}; // baseId -> [megaId, ...]
const MEGA_REVERSE = {}; // megaId -> baseId
(function buildMegaMap() {
  // Group by dex number
  const byNum = {};
  POKEMON.forEach(p => {
    if (!byNum[p.num]) byNum[p.num] = [];
    byNum[p.num].push(p);
  });
  Object.values(byNum).forEach(group => {
    const bases = group.filter(p => !p.name.startsWith('Mega '));
    const megas = group.filter(p => p.name.startsWith('Mega '));
    if (megas.length === 0) return;
    // Link each base to its mega(s). If multiple bases (regional forms), link by position.
    bases.forEach((base, i) => {
      // For Charizard: 2 megas for 1 base. For most: 1 mega per base.
      if (bases.length === 1) {
        MEGA_MAP[base.id] = megas.map(m => m.id);
        megas.forEach(m => MEGA_REVERSE[m.id] = base.id);
      } else {
        // Multiple bases (regional forms) â try to match by index if megas exist
        const megaForBase = megas[i];
        if (megaForBase) {
          MEGA_MAP[base.id] = [megaForBase.id];
          MEGA_REVERSE[megaForBase.id] = base.id;
        }
      }
    });
  });
})();

